    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>feComponentTransfer</span> <span class="token attr-name">in</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>SourceGraphic<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
